  1	import * as React from 'react';
  2	import { Button, Tooltip } from '@patternfly/react-core';
  3	import { KialiAppState } from 'store/Store';
  4	import { connect } from 'react-redux';
  5	import { KIALI_THEME, PF_THEME_DARK, Theme } from 'types/Common';
  6	import { GlobalActions } from 'actions/GlobalActions';
  7	import { store } from 'store/ConfigStore';
  8	import { kialiStyle } from 'styles/StyleUtils';
  9	import { PFColors } from 'components/Pf/PfColors';
 10	import { KialiIcon } from 'config/KialiIcon';
 11	import { classes } from 'typestyle';
 12	import { useKialiTranslation } from 'utils/I18nUtils';
 13	
 14	const iconStyle = kialiStyle({
 15	  color: PFColors.Color100
 16	});
 17	
 18	const buttonStyle = kialiStyle({
 19	  fontSize: '1rem',
 20	  $nest: {
 21	    '&.pf-m-primary': {
 22	      backgroundColor: PFColors.Blue400,
 23	      $nest: {
 24	        '&::after': {
 25	          border: `1px solid ${PFColors.Blue200}`
 26	        }
 27	      }
 28	    },
 29	    '&.pf-m-secondary::after': {
 30	      border: `1px solid ${PFColors.Color400}`
 31	    }
 32	  }
 33	});
 34	
 35	const lightButtonStyle = kialiStyle({
 36	  borderTopRightRadius: 0,
 37	  borderBottomRightRadius: 0,
 38	  $nest: {
 39	    '&::after': {
 40	      borderTopRightRadius: 0,
 41	      borderBottomRightRadius: 0
 42	    },
 43	    '&&.pf-m-secondary::after': {
 44	      borderRight: 0
 45	    }
 46	  }
 47	});
 48	
 49	const darkButtonStyle = kialiStyle({
 50	  borderTopLeftRadius: 0,
 51	  borderBottomLeftRadius: 0,
 52	  $nest: {
 53	    '&::after': {
 54	      borderTopLeftRadius: 0,
 55	      borderBottomLeftRadius: 0
 56	    },
 57	    '&&.pf-m-secondary::after': {
 58	      borderLeft: 0
 59	    }
 60	  }
 61	});
 62	
 63	type ThemeSwitchProps = {
 64	  theme: string;
 65	};
 66	
 67	export const ThemeSwitchComponent: React.FC<ThemeSwitchProps> = (props: ThemeSwitchProps) => {
 68	  const { t } = useKialiTranslation();
 69	
 70	  const darkTheme = props.theme === Theme.DARK;
 71	
 72	  const handleTheme = (): void => {
 73	    const theme = darkTheme ? Theme.LIGHT : Theme.DARK;
 74	
 75	    document.documentElement.classList.toggle(PF_THEME_DARK);
 76	    store.dispatch(GlobalActions.setTheme(theme));
 77	    localStorage.setItem(KIALI_THEME, theme);
 78	  };
 79	
 80	  return (
 81	    <Tooltip position="bottom" content={<>{t('Switch to {{theme}} Mode', { theme: darkTheme ? 'Light' : 'Dark' })}</>}>
 82	      <div>
 83	        <Button
 84	          variant={darkTheme ? 'secondary' : 'primary'}
 85	          className={classes(buttonStyle, lightButtonStyle)}
 86	          onClick={handleTheme}
 87	        >
 88	          <KialiIcon.Sun className={iconStyle}></KialiIcon.Sun>
 89	        </Button>
 90	        <Button
 91	          variant={darkTheme ? 'primary' : 'secondary'}
 92	          className={classes(buttonStyle, darkButtonStyle)}
 93	          onClick={handleTheme}
 94	        >
 95	          <KialiIcon.Moon className={iconStyle}></KialiIcon.Moon>
 96	        </Button>
 97	      </div>
 98	    </Tooltip>
 99	  );
100	};
101	
102	const mapStateToProps = (state: KialiAppState): ThemeSwitchProps => {
103	  return {
104	    theme: state.globalState.theme
105	  };
106	};
107	
108	export const ThemeSwitch = connect(mapStateToProps)(ThemeSwitchComponent);

